def get_all_nba_complete_roster():
    """Get all NBA players with full metadata - truly unique"""
    players = []
    seen_names = set()  # Track unique players
    
    for team_code, team_players in NBA_COMPLETE_ROSTER.items():
        for player in team_players:
            player_key = player['name'].split('(')[0].strip()  # Remove team suffix for uniqueness
            
            # Only add if we haven't seen this player
            if player_key not in seen_names:
                seen_names.add(player_key)
                players.append({
                    **player,
                    "team": team_code,
                })
    
    return players


def get_team_roster(team_code):
    """Get roster for specific team"""
    return NBA_COMPLETE_ROSTER.get(team_code, [])


def find_player(name):
    """Find player by name across all teams"""
    for team_code, players in NBA_COMPLETE_ROSTER.items():
        for player in players:
            if player['name'].split('(')[0].strip().lower() == name.lower():
                return {**player, "team": team_code}
    return None


if __name__ == "__main__":
    players = get_all_nba_complete_roster()
    print(f"Total Unique NBA Players: {len(players)}")
    print(f"Teams: {len(NBA_COMPLETE_ROSTER)}")
